using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_Result_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsGreetingWithMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsGreetingWithTitle()
    {
        var result = _formatter.BuildGreeting("Smith", "Dr.");

        Assert.AreEqual("Dear Dr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_Result_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones");

        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_Result_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_Result_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Ms.");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpaceName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithHyphens()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_Trimmed()
    {
        var result = _formatter.GenerateSlug("  My Post  ");

        StringAssert.StartsWith(result, "my");
        StringAssert.EndsWith(result, "post");
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_AllLowercase()
    {
        var result = _formatter.GenerateSlug("TDD Best Practices");

        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex("^[a-z0-9-]+$"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpaceTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_FormattedCorrectly()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        StringAssert.Contains(result, "-");
    }
}

